long long solve(long long n, vector<vector<long long>> edges, string label) {
    vector<vector<long long>> adj(n);
    for (auto& e : edges) {
        long long u = e[0], v = e[1];
        adj[u].push_back(v);
        adj[v].push_back(u);
    }

    long long max_len = 1;

    auto is_palindrome = [](const vector<char>& s) {
        int left = 0, right = s.size() - 1;
        while (left < right) {
            if (s[left] != s[right]) return false;
            left++;
            right--;
        }
        return true;
    };

    auto dfs = [&](long long u, long long mask, const vector<char>& path) {
        if (is_palindrome(path)) {
            max_len = max(max_len, static_cast<long long>(path.size()));
        }
        for (long long v : adj[u]) {
            if (!(mask & (1 << v))) {
                vector<char> new_path = path;
                new_path.push_back(label[v]);
                dfs(v, mask | (1 << v), new_path);
            }
        }
    };

    for (long long start = 0; start < n; ++start) {
        vector<char> initial_path = {label[start]};
        dfs(start, 1 << start, initial_path);
    }

    return max_len;
}

