def solve(n: Long, edges: Array[Array[Long]], label: String): Long = {
  val adj = Array.fill(n.toInt)(Array[Long]())
  for (edge <- edges) {
    val u = edge(0)
    val v = edge(1)
    adj(u.toInt) = adj(u.toInt) :+ v
    adj(v.toInt) = adj(v.toInt) :+ u
